134	        if (type == WorkOrderEventType.RESOLUTION_CONFIRMED) {
135	            wo.setResolvedAt(OffsetDateTime.now());
136	            wo.setStatus(WorkOrderStatus.RESOLVED);
137	            // Q12: auto-lock cost on resolution so it can no longer be edited
138	            workOrderCostRepository.findByWorkOrderId(workOrderId).ifPresent(cost -> {
139	                if (cost.getLockedAt() == null) {
140	                    cost.setLockedAt(OffsetDateTime.now());
141	                    cost.setApprovedStatus("APPROVED");
142	                    workOrderCostRepository.save(cost);
143	                }
144	            });
145	        }
146	        if (type == WorkOrderEventType.STATUS_UPDATED) {
147	            // Keep current status unless specified
148	            wo.setStatus(WorkOrderStatus.IN_PROGRESS);
149	        }
150	        workOrderRepository.save(wo);
151	
152	        return toResponse(wo);
153	    }
