237	    public WorkOrderAnalyticsResponse getAnalytics(LocalDate from, LocalDate to,
238	                                                    UUID technicianId, String statusStr) {
239	        // RLS: callers without ADMIN:READ can only see their own work orders
240	        if (!SecurityUtils.hasPermission("ADMIN", "READ")) {
241	            technicianId = SecurityUtils.getCurrentUserId();
242	        }
243	        WorkOrderStatus status = null;
244	        if (statusStr != null && !statusStr.isBlank()) {
245	            try { status = WorkOrderStatus.valueOf(statusStr); } catch (Exception e) { /* ignore */ }
246	        }
247	        OffsetDateTime fromDt = from != null
248	                ? from.atStartOfDay().atOffset(ZoneOffset.UTC)
249	                : OffsetDateTime.now().minusYears(10);
250	        OffsetDateTime toDt = to != null
251	                ? to.plusDays(1).atStartOfDay().atOffset(ZoneOffset.UTC)
252	                : OffsetDateTime.now().plusDays(1);
253	
254	        List<WorkOrder> orders = workOrderRepository.findForAnalytics(technicianId, status, fromDt, toDt);
255	
256	        long submitted = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.SUBMITTED).count();
257	        long assigned = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.ASSIGNED).count();
258	        long inProgress = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.IN_PROGRESS).count();
259	        long resolved = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.RESOLVED).count();
260	        long closed = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.CLOSED).count();
261	
262	        double avgRating = orders.stream()
263	                .mapToInt(w -> workOrderRatingRepository.findByWorkOrderId(w.getId())
264	                        .map(WorkOrderRating::getRating).orElse(0))
265	                .filter(r -> r > 0)
266	                .average().orElse(0.0);
267	
268	        BigDecimal totalParts = orders.stream()
269	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
270	                        .map(WorkOrderCost::getPartsCost).orElse(BigDecimal.ZERO))
271	                .reduce(BigDecimal.ZERO, BigDecimal::add);
272	
273	        BigDecimal totalLabor = orders.stream()
274	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
275	                        .map(WorkOrderCost::getLaborCost).orElse(BigDecimal.ZERO))
276	                .reduce(BigDecimal.ZERO, BigDecimal::add);
277	
278	        return WorkOrderAnalyticsResponse.builder()
279	                .total(orders.size())
280	                .submitted(submitted)
281	                .assigned(assigned)
282	                .inProgress(inProgress)
283	                .resolved(resolved)
284	                .closed(closed)
285	                .avgRating(avgRating)
286	                .totalPartsCost(totalParts)
287	                .totalLaborCost(totalLabor)
288	                .build();
289	    }
