209	    @Transactional
210	    public OrderResponse confirmPayment(UUID orderId, String paymentRef) {
211	        permissionEnforcer.require("ORDER", "WRITE");
212	        Order order = orderRepository.findById(orderId)
213	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
214	        assertOrderOwnership(order, true);
215	
216	        if (order.getStatus() != OrderStatus.PLACED) {
217	            throw new AppException("INVALID_STATE_TRANSITION",
218	                    "Order must be in PLACED status to confirm payment", HttpStatus.CONFLICT);
219	        }
220	
221	        order.setStatus(OrderStatus.CONFIRMED_PAYMENT);
222	        order.setPaymentConfirmedAt(OffsetDateTime.now());
223	        orderRepository.save(order);
224	
225	        // Accrue points for member
226	        memberRepository.findByUserId(order.getBuyerUserId()).ifPresent(member ->
227	            memberService.accruePoints(member.getId(), orderId, order.getTotalPayable())
228	        );
229	
230	        auditService.record(order.getBuyerUserId(), "ORDER", orderId.toString(),
231	                "CONFIRM_PAYMENT", "PAYMENT_CONFIRMED", OrderStatus.PLACED, OrderStatus.CONFIRMED_PAYMENT);
232	
233	        return toResponse(order);
234	    }
235	
236	    @Transactional
237	    public OrderResponse fulfillOrder(UUID orderId) {
238	        permissionEnforcer.require("ORDER", "WRITE");
239	        Order order = orderRepository.findById(orderId)
240	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
241	        assertOrderOwnership(order, true);
242	
243	        if (order.getStatus() != OrderStatus.CONFIRMED_PAYMENT) {
244	            throw new AppException("INVALID_STATE_TRANSITION",
245	                    "Order must be in CONFIRMED_PAYMENT status to fulfill", HttpStatus.CONFLICT);
246	        }
247	
248	        // Q9: All-or-nothing fulfillment — verify that reserved inventory still covers
249	        // ALL items before transitioning. If the reservation window expired and the
250	        // timeout job already released stock for some SKUs, we must not partially fulfill.
251	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
252	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
253	        for (OrderItem item : items) {
254	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
255	        }
256	
257	        List<String> insufficientSkus = new ArrayList<>();
258	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
259	            Inventory inv = inventoryRepository.findBySkuWithLock(entry.getKey())
260	                    .orElse(null);
261	            if (inv == null || inv.getReserved() < entry.getValue()) {
262	                insufficientSkus.add(entry.getKey());
263	            }
264	        }
265	        if (!insufficientSkus.isEmpty()) {
266	            throw new AppException("FULFILLMENT_INVENTORY_INSUFFICIENT",
267	                    "Cannot fulfill: insufficient reserved inventory for SKU(s): " +
268	                    String.join(", ", insufficientSkus),
269	                    HttpStatus.UNPROCESSABLE_ENTITY);
270	        }
271	
272	        order.setStatus(OrderStatus.FULFILLMENT_RESERVED);
273	        orderRepository.save(order);
274	
275	        auditService.record(order.getBuyerUserId(), "ORDER", orderId.toString(),
276	                "FULFILL_ORDER", "USER_ACTION",
277	                Map.of("status", OrderStatus.CONFIRMED_PAYMENT.name()),
278	                Map.of("status", OrderStatus.FULFILLMENT_RESERVED.name()));
279	
280	        return toResponse(order);
281	    }
