283	    @Transactional
284	    public OrderResponse confirmDelivery(UUID orderId) {
285	        permissionEnforcer.require("ORDER", "WRITE");
286	        Order order = orderRepository.findById(orderId)
287	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
288	        assertOrderOwnership(order, true);
289	
290	        if (order.getStatus() != OrderStatus.FULFILLMENT_RESERVED) {
291	            throw new AppException("INVALID_STATE_TRANSITION",
292	                    "Order must be in FULFILLMENT_RESERVED status", HttpStatus.CONFLICT);
293	        }
294	        order.setStatus(OrderStatus.DELIVERY_CONFIRMED);
295	        orderRepository.save(order);
296	
297	        // Deduct from inventory reservation
298	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
299	        for (OrderItem item : items) {
300	            inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
301	                inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
302	                inv.setOnHand(Math.max(0, inv.getOnHand() - item.getQuantity()));
303	                inventoryRepository.save(inv);
304	            });
305	        }
306	
307	        auditService.record(order.getBuyerUserId(), "ORDER", orderId.toString(),
308	                "CONFIRM_DELIVERY", "USER_ACTION",
309	                Map.of("status", OrderStatus.FULFILLMENT_RESERVED.name()),
310	                Map.of("status", OrderStatus.DELIVERY_CONFIRMED.name()));
311	
312	        return toResponse(order);
313	    }
