409	    private BigDecimal computeShipping(String country) {
410	        // Simple flat rate
411	        if ("US".equalsIgnoreCase(country)) return BigDecimal.valueOf(10.00);
412	        if (country == null) return BigDecimal.valueOf(15.00);
413	        return BigDecimal.valueOf(25.00);
414	    }
415	
416	    private String hashIdempotencyKey(UUID buyerId, String key) {
417	        try {
418	            MessageDigest md = MessageDigest.getInstance("SHA-256");
419	            byte[] hash = md.digest((buyerId.toString() + ":" + key).getBytes(StandardCharsets.UTF_8));
420	            StringBuilder sb = new StringBuilder();
421	            for (byte b : hash) sb.append(String.format("%02x", b));
422	            return sb.toString();
423	        } catch (Exception e) {
424	            return key;
425	        }
426	    }
427	
428	    public OrderResponse toResponse(Order order) {
429	        // Load items from DB (since items is @Transient on Order)
430	        List<OrderItem> dbItems = order.getItems() != null && !order.getItems().isEmpty()
431	                ? order.getItems()
432	                : orderItemRepository.findByOrderId(order.getId());
433	        List<OrderItemResponse> itemResponses = dbItems.stream()
434	                .map(this::toItemResponse).collect(Collectors.toList());
435	
436	        return OrderResponse.builder()
437	                .id(order.getId())
438	                .orderNumber(order.getOrderNumber())
439	                .buyerUserId(order.getBuyerUserId())
440	                .status(order.getStatus())
441	                .subtotal(order.getSubtotal())
442	                .discountsTotal(order.getDiscountsTotal())
443	                .shippingTotal(order.getShippingTotal())
444	                .totalPayable(order.getTotalPayable())
445	                .paymentMethod(order.getPaymentMethod())
446	                .shippingCountry(order.getShippingCountry())
447	                .shippingPostalCode(order.getShippingPostalCode())
448	                .items(itemResponses)
449	                .createdAt(order.getCreatedAt())
450	                .closedAt(order.getClosedAt())
451	                .paymentConfirmedAt(order.getPaymentConfirmedAt())
452	                .build();
453	    }
454	
455	    private OrderItemResponse toItemResponse(OrderItem item) {
456	        return OrderItemResponse.builder()
457	                .id(item.getId())
458	                .sku(item.getSku())
459	                .quantity(item.getQuantity())
460	                .unitPrice(item.getUnitPrice())
461	                .lineTotal(item.getLineTotal())
462	                .build();
463	    }
464	}
