107	    @Transactional
108	    public void resolveModeration(UUID queueItemId, String decision, String reason, UUID actorId) {
109	        permissionEnforcer.require("ADMIN", "WRITE");
110	
111	        ModerationQueue item = moderationQueueRepository.findById(queueItemId)
112	                .orElseThrow(() -> new AppException("NOT_FOUND",
113	                        "Moderation queue item not found: " + queueItemId, HttpStatus.NOT_FOUND));
114	
115	        if (!"PENDING".equals(item.getStatus())) {
116	            throw new AppException("ALREADY_RESOLVED",
117	                    "Moderation item has already been resolved with status: " + item.getStatus(),
118	                    HttpStatus.CONFLICT);
119	        }
120	
121	        String newStatus = "APPROVE".equalsIgnoreCase(decision) ? "APPROVED" : "REJECTED";
122	        item.setStatus(newStatus);
123	        moderationQueueRepository.save(item);
124	
125	        // Propagate decision to the target entity
126	        if ("OUTCOME".equals(item.getTargetType())) {
127	            outcomeRepository.findById(item.getTargetId()).ifPresent(outcome -> {
128	                outcome.setStatus("APPROVE".equalsIgnoreCase(decision) ? "ACTIVE" : "REJECTED");
129	                outcomeRepository.save(outcome);
130	            });
131	        }
132	
133	        auditService.record(actorId, "MODERATION_QUEUE", queueItemId.toString(),
134	                "RESOLVE_MODERATION", "ADMIN_MODERATION",
135	                Map.of("status", "PENDING", "targetType", item.getTargetType(),
136	                        "targetId", item.getTargetId().toString()),
137	                Map.of("status", newStatus, "decision", decision,
138	                        "reason", reason != null ? reason : ""));
139	    }
