195	    private byte[] exportOrdersExcel(List<Order> orders) {
196	        try (Workbook wb = new XSSFWorkbook(); ByteArrayOutputStream out = new ByteArrayOutputStream()) {
197	            Sheet sheet = wb.createSheet("Orders");
198	            String[] headers = {"ID", "Order Number", "Buyer ID", "Status",
199	                    "Subtotal", "Discounts", "Shipping", "Total", "Payment Method", "Created At"};
200	            Row headerRow = sheet.createRow(0);
201	            for (int i = 0; i < headers.length; i++) {
202	                headerRow.createCell(i).setCellValue(headers[i]);
203	            }
